// Normalize and enrich incoming funnel event
const body = $input.first().json.body || $input.first().json;

const normalized = {
  timestamp: new Date().toISOString(),
  session_id: body.sessionId || body.session_id || 'unknown',
  page_url: body.pageUrl || body.page_url || '',
  page_title: body.pageTitle || body.page_title || '',
  event_type: body.eventType || body.event_type || '',
  event_value: body.eventValue || body.event_value || '',
  scroll_depth: body.scrollDepth || body.scroll_depth || 0,
  time_on_page: body.timeOnPage || body.time_on_page || 0,
  button_id: body.buttonId || body.button_id || '',
  quiz_step: body.quizStep || body.quiz_step || '',
  user_agent: body.userAgent || body.user_agent || '',
  referrer: body.referrer || '',
  utm_source: body.utmSource || body.utm_source || '',
  utm_medium: body.utmMedium || body.utm_medium || '',
  utm_campaign: body.utmCampaign || body.utm_campaign || ''
};

return [{ json: normalized }];

// Aggregate events from the past 7 days for OpenAI analysis
const items = $input.all();
const oneWeekAgo = new Date();
oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);

const recentEvents = items.filter(item => {
  const ts = new Date(item.json.Timestamp || item.json.timestamp);
  return ts >= oneWeekAgo;
});

// Count event types
const eventCounts = {};
const pageCounts = {};
const buttonClicks = {};
const quizSteps = {};
let totalScrollDepth = 0;
let totalTimeOnPage = 0;
let scrollCount = 0;
let timeCount = 0;

for (const e of recentEvents) {
  const type = e.json.Event_Type || e.json.event_type || 'unknown';
  const page = e.json.Page_URL || e.json.page_url || 'unknown';
  const btn = e.json.Button_ID || e.json.button_id || '';
  const quiz = e.json.Quiz_Step || e.json.quiz_step || '';
  const scroll = parseFloat(e.json.Scroll_Depth || 0);
  const time = parseFloat(e.json.Time_On_Page || 0);

  eventCounts[type] = (eventCounts[type] || 0) + 1;
  pageCounts[page] = (pageCounts[page] || 0) + 1;
  if (btn) buttonClicks[btn] = (buttonClicks[btn] || 0) + 1;
  if (quiz) quizSteps[quiz] = (quizSteps[quiz] || 0) + 1;
  if (scroll > 0) { totalScrollDepth += scroll; scrollCount++; }
  if (time > 0) { totalTimeOnPage += time; timeCount++; }
}

const summary = {
  period: `${oneWeekAgo.toDateString()} - ${new Date().toDateString()}`,
  total_events: recentEvents.length,
  event_type_breakdown: eventCounts,
  page_visit_counts: pageCounts,
  button_clicks: buttonClicks,
  quiz_step_completions: quizSteps,
  avg_scroll_depth_pct: scrollCount > 0 ? (totalScrollDepth / scrollCount).toFixed(1) : 0,
  avg_time_on_page_sec: timeCount > 0 ? (totalTimeOnPage / timeCount).toFixed(0) : 0
};

return [{ json: { summary, summaryText: JSON.stringify(summary, null, 2) } }];

